INSERT INTO insights (id, title, "contentType", summary, body, author, "publishedAt", "isPremium", tags) VALUES ('in_007aa0kg', 'Global Oncology Market Report 2024', 'Market Report', 'Comprehensive analysis of the global oncology therapeutics market reaching $300B+', 'The global oncology market continues to expand driven by immunotherapy advances and precision medicine. Key growth areas include ADCs and bispecific antibodies.', 'WHAI Research', '2024-06-01T00:00:00.000Z', true, 'oncology;market-report;immunotherapy');
INSERT INTO insights (id, title, "contentType", summary, body, author, "publishedAt", "isPremium", tags) VALUES ('in_00c1kf1c', 'AI in Drug Discovery: State of Play', 'Analysis', 'How artificial intelligence is reshaping pharmaceutical R&D pipelines', 'AI-driven drug discovery is accelerating timelines from target identification to clinical candidates. Major pharma companies are investing heavily in ML platforms.', 'Sarah Mitchell', '2024-03-15T00:00:00.000Z', false, 'AI;drug-discovery;R&D');
INSERT INTO insights (id, title, "contentType", summary, body, author, "publishedAt", "isPremium", tags) VALUES ('in_004fr9ee', 'Digital Health Funding Q1 2024', 'Data Snapshot', 'Quarterly overview of digital health venture funding and M&A activity', 'Digital health funding reached $3.2B in Q1 2024 marking a stabilization after the 2022-2023 correction. Telehealth and AI diagnostics lead deal volume.', 'WHAI Data Team', '2024-04-01T00:00:00.000Z', false, 'digital-health;funding;venture-capital');
INSERT INTO insights (id, title, "contentType", summary, body, author, "publishedAt", "isPremium", tags) VALUES ('in_0010cr5z', 'mRNA Therapeutics Beyond Vaccines', 'Analysis', 'The expanding frontier of mRNA technology into oncology and rare diseases', 'Following COVID-19 vaccine success mRNA platforms are being developed for cancer vaccines personalized neoantigen therapies and rare genetic disorders.', 'Dr. James Ward', '2024-05-20T00:00:00.000Z', true, 'mRNA;oncology;rare-disease');
INSERT INTO insights (id, title, "contentType", summary, body, author, "publishedAt", "isPremium", tags) VALUES ('in_00gv0ouh', 'Healthcare M&A Outlook 2024', 'Market Report', 'Strategic review of healthcare mergers and acquisitions trends', 'Healthcare M&A activity is rebounding with pharma companies pursuing bolt-on acquisitions in oncology and rare disease. PE activity remains strong in health IT.', 'WHAI Research', '2024-01-10T00:00:00.000Z', true, 'M&A;strategy;private-equity');
INSERT INTO insights (id, title, "contentType", summary, body, author, "publishedAt", "isPremium", tags) VALUES ('in_00wybi2y', 'Precision Medicine Data Infrastructure', 'Analysis', 'Building the data backbone for precision medicine at scale', 'Healthcare systems are investing in genomic data infrastructure interoperability standards and clinical decision support systems powered by real-world evidence.', 'Elena Rodriguez', '2024-07-01T00:00:00.000Z', false, 'precision-medicine;data;infrastructure');
INSERT INTO insights (id, title, "contentType", summary, body, author, "publishedAt", "isPremium", tags) VALUES ('in_00454pgd', 'GLP-1 Market Disruption Report', 'Market Report', 'How GLP-1 receptor agonists are reshaping cardiometabolic care', 'The GLP-1 market is projected to exceed $100B by 2030 with expanding indications beyond diabetes into obesity NASH and cardiovascular risk reduction.', 'WHAI Research', '2024-08-15T00:00:00.000Z', true, 'GLP-1;obesity;cardiovascular');
INSERT INTO insights (id, title, "contentType", summary, body, author, "publishedAt", "isPremium", tags) VALUES ('in_0009rkub', 'Biotech IPO Window Analysis', 'Data Snapshot', 'Analysis of biotech IPO market conditions and pipeline companies', 'The biotech IPO window has reopened with improved market conditions. Companies with differentiated platforms and Phase 2+ data are finding investor appetite.', 'WHAI Data Team', '2024-09-01T00:00:00.000Z', false, 'biotech;IPO;capital-markets');
